mapper.insert:
	 MERGE INTO STOCECCT A
	 USING (SELECT #{ses.gateCd} AS GATE_CD
	             , #{BUYER_CD}   AS BUYER_CD
	     		 , #{CONT_NUM}   AS CONT_NUM
	     		 , #{CONT_CNT}   AS CONT_CNT
	     		 ) B
            ON (A.GATE_CD  = B.GATE_CD
            AND A.BUYER_CD = B.BUYER_CD
            AND A.CONT_NUM = B.CONT_NUM
            AND A.CONT_CNT = B.CONT_CNT
            AND A.DEL_FLAG = '0')
	   WHEN MATCHED THEN
	 UPDATE SET
	        MOD_DATE = SYSDATE
	      , MOD_USER_ID = #{ses.userId}
	      , PROGRESS_CD = #{PROGRESS_CD}
	      , CONT_DATE = #{CONT_DATE}
	      , ORIGIN_CONT_START_DATE = #{ORIGIN_CONT_START_DATE}
		  , CONT_START_DATE = #{CONT_START_DATE}
		  , CONT_END_DATE = #{CONT_END_DATE}
		  , CONT_DESC = #{CONT_DESC}
		  , CONT_REQ_CD = '10'
		  , CONT_AMT = #{CONT_AMT}
		  , CUR = #{CUR}
		  , VAT_TYPE = #{VAT_TYPE}
		  , SUPPLY_AMT = (CASE WHEN #{VAT_TYPE} = '1' THEN TRUNC(TO_NUMBER(#{CONT_AMT}) / 1.1)
					           WHEN #{VAT_TYPE} = '2' THEN TO_NUMBER(#{CONT_AMT})
					           WHEN #{VAT_TYPE} = '0' THEN TO_NUMBER(#{CONT_AMT}) END)
		  , VAT_AMT = (CASE WHEN #{VAT_TYPE} = '1' THEN TO_NUMBER(#{CONT_AMT}) - TRUNC(TO_NUMBER(#{CONT_AMT}) / 1.1)
					        WHEN #{VAT_TYPE} = '2' THEN TRUNC(TO_NUMBER(#{CONT_AMT}) * 0.1)
					        WHEN #{VAT_TYPE} = '0' THEN 0 END)
		  , CONT_RMK = #{CONT_RMK}
		  , DEPT_CD = (SELECT DEPT_CD FROM STOCCVUR
				  	   	WHERE GATE_CD = #{ses.gateCd}
				  	   	  AND USER_ID = #{CONT_USER_ID})
	      , CONT_USER_ID = #{CONT_USER_ID}
	      , ATT_FILE_NUM = #{ATT_FILE_NUM}
	      , SIGN_STATUS = (CASE WHEN #{PROGRESS_CD} = '4300' THEN 'E' ELSE 'T' END)
	      , SIGN_DATE = (CASE WHEN #{PROGRESS_CD} = '4300' THEN SYSDATE ELSE null END)
	      , MANUAL_CONT_FLAG = '1'
	   WHEN NOT MATCHED THEN
	 INSERT (
		    GATE_CD
		  , BUYER_CD
		  , CONT_NUM
		  , CONT_CNT
		  , REG_DATE
		  , REG_USER_ID
		  , MOD_DATE
		  , MOD_USER_ID
		  , DEL_FLAG
		  , PROGRESS_CD
		  , CONT_DATE
		  , ORIGIN_CONT_START_DATE
		  , CONT_START_DATE
		  , CONT_END_DATE
		  , CONT_DESC
		  , CONT_REQ_CD
		  , CONT_AMT
		  , CUR
		  , VAT_TYPE
		  , SUPPLY_AMT
		  , VAT_AMT
		  , CONT_RMK
		  , DEPT_CD
		  , CONT_USER_ID
		  , VENDOR_CD
		  , ATT_FILE_NUM
		  , SIGN_STATUS
		  , SIGN_DATE
		  , MANUAL_CONT_FLAG
	) VALUES (
	  	    #{ses.gateCd}
	  	  , (#{BUYER_CD}, #{ses.companyCd})
	  	  , #{CONT_NUM}
	  	  , #{CONT_CNT}
	  	  , SYSDATE
		  , #{ses.userId}
		  , SYSDATE
		  , #{ses.userId}
		  , '0'
		  , #{PROGRESS_CD}
	  	  , #{CONT_DATE}
	  	  , #{ORIGIN_CONT_START_DATE}
	  	  , #{CONT_START_DATE}
	  	  , #{CONT_END_DATE}
	  	  , #{CONT_DESC}
	  	  , '10'						-- CONT_REQ_CD : 신규(10)
	  	  , #{CONT_AMT}
	  	  , #{CUR}
	  	  , #{VAT_TYPE}
		  ,(CASE WHEN #{VAT_TYPE} = '1' THEN TRUNC(TO_NUMBER(#{CONT_AMT}) / 1.1)
		         WHEN #{VAT_TYPE} = '2' THEN TO_NUMBER(#{CONT_AMT})
		         WHEN #{VAT_TYPE} = '0' THEN TO_NUMBER(#{CONT_AMT}) END)
		  ,(CASE WHEN #{VAT_TYPE} = '1' THEN TO_NUMBER(#{CONT_AMT}) - TRUNC(TO_NUMBER(#{CONT_AMT}) / 1.1)
		         WHEN #{VAT_TYPE} = '2' THEN TRUNC(TO_NUMBER(#{CONT_AMT}) * 0.1)
		         WHEN #{VAT_TYPE} = '0' THEN 0 END)
	  	  , #{CONT_RMK}
	  	  ,(SELECT DEPT_CD FROM STOCCVUR
	  	   	 WHERE GATE_CD = #{ses.gateCd}
	  	   	   AND USER_ID = #{CONT_USER_ID})
	  	  , #{CONT_USER_ID}
	  	  , #{VENDOR_CD}
	  	  , #{ATT_FILE_NUM}
	  	  ,(CASE WHEN #{PROGRESS_CD} = '4300' THEN 'E' ELSE 'T' END)
	  	  ,(CASE WHEN #{PROGRESS_CD} = '4300' THEN SYSDATE ELSE null END)
	  	  , '1'							-- MANUAL_CONT_FLAG
	)

