UPDATE STOCECHB A
   SET MOD_DATE = SYSDATE
	 , MOD_USER_ID = #{ses.userId}
	 , DEL_FLAG = '0'
 WHERE A.GATE_CD  = #{ses.gateCd}
   AND A.BUYER_CD = #{ses.companyCd}
   AND A.CONT_WT_NUM IN (SELECT CONT_WT_NUM FROM STOCECMT
   						  WHERE GATE_CD  = A.GATE_CD
   						    AND BUYER_CD = A.BUYER_CD
   						    AND CONT_NUM = #{CONT_NUM}
   						    AND CONT_CNT = #{CONT_CNT}
   						    AND EXEC_NUM = A.EXEC_NUM
   						    AND EXEC_SQ  = A.EXEC_SQ)

