UPDATE STOCPRDT
   SET MOD_DATE    = SYSDATE
	 , MOD_USER_ID = #{ses.userId}
	 , PROGRESS_CD = '4300'
 WHERE GATE_CD  = #{ses.gateCd}
   AND (BUYER_CD, PR_NUM, PR_SQ) IN (
		   		SELECT PB_BUYER_CD, PR_NUM, PR_SQ
		   		  FROM STOCECMT
		   		 WHERE GATE_CD  = #{ses.gateCd}
		   		   AND BUYER_CD = #{BUYER_CD}
		   		   AND CONT_NUM = #{CONT_NUM}
		   		   AND CONT_CNT = #{CONT_CNT}
		   		   AND DEL_FLAG = '0')
   AND DEL_FLAG = '0'
